require('dotenv').config();
const { generateText } = require('ai');
const { openai } = require('@ai-sdk/openai');
const { InconvoClient } = require('@inconvoai/node');
const { createInconvoTool } = require('@inconvoai/vercel-ai-sdk');
const fs = require('fs');
const path = require('path');

async function main() {
  console.log('Initializing Inconvo agent...');

  // Read environment variables
  const inconvoApiKey = process.env.INCONVO_API_KEY;
  const inconvoAgentId = process.env.INCONVO_AGENT_ID;
  const inconvoDbUrl = process.env.INCONVO_DB_URL;
  const openaiApiKey = process.env.OPENAI_API_KEY;

  if (!inconvoApiKey || !inconvoAgentId || !inconvoDbUrl || !openaiApiKey) {
    throw new Error('Missing required environment variables. Please ensure INCONVO_API_KEY, INCONVO_AGENT_ID, INCONVO_DB_URL, and OPENAI_API_KEY are set.');
  }

  // Initialize Inconvo client
  const inconvoClient = new InconvoClient({
    apiKey: inconvoApiKey,
    agentId: inconvoAgentId,
    dbUrl: inconvoDbUrl
  });

  // Create Inconvo tool for Vercel AI SDK
  const inconvoTool = createInconvoTool(inconvoClient);

  console.log('Calling agent with question: "What is the total amount of orders?"');

  // Generate text using Vercel AI SDK with OpenAI model
  const result = await generateText({
    model: openai('gpt-4o'),
    tools: {
      queryDatabase: inconvoTool
    },
    prompt: 'What is the total amount of orders?',
    temperature: 0
  });

  console.log('Agent response:', result.text);

  // Save response to response.json
  const responseObj = {
    response: result.text
  };

  const responsePath = path.join(__dirname, 'response.json');
  fs.writeFileSync(responsePath, JSON.stringify(responseObj, null, 2), 'utf-8');
  console.log(`Response saved to ${responsePath}`);

  return result.text;
}

// Run the main function
main()
  .then(() => {
    console.log('Agent completed successfully');
    process.exit(0);
  })
  .catch((error) => {
    console.error('Error:', error.message);
    console.error(error.stack);
    process.exit(1);
  });

